// interface defines a contract for object shapes
interface User {
  id: number;   // every user needs a unique id
  name: string; // display name shown in the UI
  email: string; // used for login and notifications
}

// ? means the property is optional and may be undefined
interface User {
  id: number;
  name: string;
  email: string;
  phone?: string;  // not everyone provides a phone number
  bio?: string;     // short description -- can be omitted
}

// readonly fields cannot be changed after object creation
interface User {
  readonly id: number; // set once, never modified
  name: string;
  email: string;
}

// Interfaces describe behavior too -- not just data
interface User {
  id: number;
  name: string;
  greet(): string;       // method signature -- takes nothing, returns string
  log(message: string): void; // method that returns nothing
}

// The object literal must include ALL required properties
const user: User = {
  id: 1,
  name: 'Alice',
  email: 'alice@example.com',
  greet() { return 'Hello!'; },
  log(msg) { console.log(msg); }
};

// extends copies all User properties into Admin
interface Admin extends User {
  role: 'admin' | 'superadmin'; // extra Admin-only property
  manageUsers(): void;           // extra Admin-only method
}

// [key: string] means any string property name is accepted
interface Dictionary {
  [key: string]: string; // all values must be strings too
}

const translations: Dictionary = {
  hello: 'bonjour',      // property name is dynamic
  goodbye: 'au revoir'
};
